{% component section %}

{% import Link from "../link/link.nz.liquid" %}

{% props {
  text: string.setting({
    label: "Text",
    default: "Free shipping on orders over $50",
  }),
  link: url.setting({
    label: "Link",
  }),
} %}

<section class="nazare-announcement-bar">
  {% if props.link != blank %}
    {% render Link {
      href: props.link,
      text: props.text,
      class: "nazare-announcement-bar__link",
    } %}
  {% else %}
    <span class="nazare-announcement-bar__text">
      {{ props.text }}
    </span>
  {% endif %}
</section>
